	jsonStart := strings.Index(out.String(), "{")
	require.NotEqual(t, -1, jsonStart, "output should contain JSON: %s", out)
	assert.NotContains(t, out.String()[:jsonStart], "route: ")

	var res struct {
		Attempts int `json:"attempts"`
		Results  []struct {
			Harness                     string  `json:"harness"`
