			PredictedCostUSDPer1kTokens float64 `json:"predicted_cost_usd_per_1k_tokens"`
			PredictedCostSource         string  `json:"predicted_cost_source"`
		} `json:"results"`
	}
	require.NoError(t, json.Unmarshal([]byte(out.String()[jsonStart:]), &res))
